package uk.gov.hmcts.cp.subscription.utils;import static org.junit.jupiter.api.Assertions.*;import org.junit.jupiter.api.Test;class SubscriptionHelperTest {    @Test    void shouldReturnNull_whenCallbackUrlIsNull() {        assertNull(SubscriptionHelper.getSanitizedCallbackUrl(null));    }    @Test    void shouldReturnEmpty_whenCallbackUrlIsEmpty() {        assertEquals("", SubscriptionHelper.getSanitizedCallbackUrl(""));    }    @Test    void shouldReturnSameContent_whenNoControlCharsPresent() {        String input = "https://example.com/callback?param=value";        assertEquals(input, SubscriptionHelper.getSanitizedCallbackUrl(input));    }    @Test    void shouldReplaceExtraChars_whenCallbackUrlContainsVariousControlsChars() {        String input = "a\r\nb\nc\rd";        String expected = "a  b c d";        assertEquals(expected, SubscriptionHelper.getSanitizedCallbackUrl(input));    }}